<template>
  <div class="login-container">
    <div class="bg-decoration"></div>

    <div class="logo-area">
      <div class="logo-seal"></div>
      <div class="app-name">中医智能问答</div>
      <div class="slogan">承古纳今 · 智问医道</div>
    </div>
    
    <div class="login-card">
      <div class="corner c-tl"></div>
      <div class="corner c-tr"></div>
      <div class="corner c-bl"></div>
      <div class="corner c-br"></div>

      <div class="welcome-text">欢迎阁下</div>
      
      <button class="login-btn" @click="handleLogin">
        <i class="ri-wechat-fill" style="font-size: 20px;"></i>
        <span>微信一键登录</span>
      </button>
      
      <div class="agreement-box">
        <div class="checkbox" :class="{ checked: isAgreed }" @click="toggleAgree"></div>
        <span>我已阅读并同意 <text class="link">用户协议</text></span>
      </div>
    </div>

    <div class="footer">
      AI 赋能传统医学 · 仅供健康参考
    </div>
  </div>
</template>

<script>
import { login } from '@/api/user.js';

export default {
  data() {
    return {
      isAgreed: false
    }
  },
  methods: {
    toggleAgree() {
      this.isAgreed = !this.isAgreed;
    },
    handleLogin() {
      if (!this.isAgreed) {
        uni.showToast({
          title: '请先同意用户协议',
          icon: 'none'
        });
        return;
      }
      
      const that = this;
      
      // 1. Get User Profile (Nickname, Avatar)
      // Note: This must be triggered by a user tap
      uni.getUserProfile({
        desc: '用于完善会员资料',
        success: (res) => {
          const userInfo = res.userInfo;
          
          uni.showLoading({
            title: '登录中...'
          });
          
          // 2. Get Login Code
          uni.login({
            provider: 'weixin',
            success: (loginRes) => {
              if (loginRes.code) {
                // 3. Call Backend Login API
                const loginDTO = {
                  code: loginRes.code,
                  nickname: userInfo.nickName,
                  avatarUrl: userInfo.avatarUrl,
                  gender: userInfo.gender
                };
                
                login(loginDTO).then(response => {
                  uni.hideLoading();
                  // Save user info to storage
                  uni.setStorageSync('userInfo', response.data);
                  
                  uni.showToast({
                    title: '登录成功',
                    icon: 'success'
                  });
                  
                  setTimeout(() => {
                    uni.reLaunch({
                      url: '/pages/index/index'
                    });
                  }, 1500);
                }).catch(error => {
                  uni.hideLoading();
                  console.error('Login failed:', error);
                });
              } else {
                uni.hideLoading();
                uni.showToast({
                  title: '获取登录凭证失败',
                  icon: 'none'
                });
              }
            },
            fail: (err) => {
              uni.hideLoading();
              console.error('uni.login failed:', err);
              uni.showToast({
                title: '登录失败',
                icon: 'none'
              });
            }
          });
        },
        fail: (err) => {
          console.log('getUserProfile failed or cancelled:', err);
          uni.showToast({
            title: '需要授权才能登录',
            icon: 'none'
          });
        }
      });
    }
  }
}
</script>

